static void cct_rt_fluxus_reverse(void *flux_ptr) {
    cct_rt_fluxus_require(flux_ptr, "fluxus reverse received null instance");
    cct_rt_fluxus_t *flux = (cct_rt_fluxus_t*)flux_ptr;
    if (flux->len <= 1) return;
    size_t elem_size = (size_t)flux->elem_size;
    unsigned char *tmp = (unsigned char*)cct_rt_alloc_or_fail(elem_size);
    unsigned char *base = (unsigned char*)flux->data;
    long long i = 0;
    long long j = flux->len - 1;
    while (i < j) {
        unsigned char *left = base + ((size_t)i * elem_size);
        unsigned char *right = base + ((size_t)j * elem_size);
        memcpy(tmp, left, elem_size);
        memcpy(left, right, elem_size);
        memcpy(right, tmp, elem_size);
        i += 1;
        j -= 1;
    }
    cct_rt_free_ptr(tmp);
}

static int cct_rt_fluxus_cmp_int(const void *a, const void *b) {
    long long av = *(const long long*)a;
    long long bv = *(const long long*)b;
    if (av < bv) return -1;
    if (av > bv) return 1;
    return 0;
}

static int cct_rt_fluxus_cmp_verbum(const void *a, const void *b) {
    const char *sa = *(const char *const *)a;
    const char *sb = *(const char *const *)b;
    return strcmp(sa ? sa : "", sb ? sb : "");
}

static void cct_rt_fluxus_sort_int(void *flux_ptr) {
    cct_rt_fluxus_require(flux_ptr, "fluxus sort_int received null instance");
    cct_rt_fluxus_t *flux = (cct_rt_fluxus_t*)flux_ptr;
    if (flux->elem_size != (long long)sizeof(long long)) cct_rt_fail("fluxus sort_int requer elem_size == sizeof(long long)");
    if (flux->len <= 1) return;
    qsort(flux->data, (size_t)flux->len, sizeof(long long), cct_rt_fluxus_cmp_int);
}

static void cct_rt_fluxus_sort_verbum(void *flux_ptr) {
    cct_rt_fluxus_require(flux_ptr, "fluxus sort_verbum received null instance");
    cct_rt_fluxus_t *flux = (cct_rt_fluxus_t*)flux_ptr;
    if (flux->elem_size != (long long)sizeof(char*)) cct_rt_fail("fluxus sort_verbum requer elem_size == sizeof(char*)");
    if (flux->len <= 1) return;
    qsort(flux->data, (size_t)flux->len, sizeof(char*), cct_rt_fluxus_cmp_verbum);
}

static int cct_rt_alg_cmp_verbum_slot(const void *a, const void *b) {
    const char *sa = *(const char *const*)a;
    const char *sb = *(const char *const*)b;
    return strcmp(sa ? sa : "", sb ? sb : "");
}

static void cct_rt_alg_sort_verbum(void *arr_ptr, long long n) {
    if (n < 0) cct_rt_fail("alg_sort_verbum n must be >= 0");
    if (n <= 1) return;
    if (!arr_ptr) cct_rt_fail("alg_sort_verbum received null array pointer");
    qsort(arr_ptr, (size_t)n, sizeof(char*), cct_rt_alg_cmp_verbum_slot);
}

