static char *cct_rt_fmt_unsigned_base(unsigned long long v, unsigned base, const char *digits, const char *prefix) {
    if (base < 2U) cct_rt_fail("fmt stringify base invalida");
    const char *alpha = digits ? digits : "0123456789abcdef";
    const char *pre = prefix ? prefix : "";
    char buf[128];
    size_t i = sizeof(buf);
    buf[--i] = '\0';
    do {
        unsigned d = (unsigned)(v % (unsigned long long)base);
        buf[--i] = alpha[d];
        v /= (unsigned long long)base;
    } while (v > 0ULL);
    size_t pre_len = strlen(pre);
    size_t body_len = strlen(buf + i);
    char *out_s = (char*)malloc(pre_len + body_len + 1);
    if (!out_s) cct_rt_fail("fmt stringify base allocation failed");
    if (pre_len > 0) memcpy(out_s, pre, pre_len);
    memcpy(out_s + pre_len, buf + i, body_len + 1);
    return out_s;
}

static char *cct_rt_fmt_stringify_int_hex(long long x) {
    unsigned long long v = (x < 0) ? (((unsigned long long)x) & 0xffffffffULL) : (unsigned long long)x;
    return cct_rt_fmt_unsigned_base(v, 16U, "0123456789abcdef", "0x");
}

