static void *cct_rt_sock_accept(void *sock_ptr) {
#ifdef _WIN32
    (void)sock_ptr;
    cct_rt_fail("sock_accept unsupported on _WIN32");
    return NULL;
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_accept recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_accept recebeu socket fechado");
    for (;;) {
        int fd = accept(sock->fd, NULL, NULL);
        if (fd >= 0) {
            cct_rt_socket_clear_last_error();
            return (void*)cct_rt_socket_alloc(fd, sock->kind, sock->domain);
        }
        if (errno == EINTR) continue;
        cct_rt_socket_set_last_error("sock_accept falhou");
        cct_rt_fail("sock_accept falhou");
    }
#endif
}

static long long cct_rt_sock_send(void *sock_ptr, const char *data) {
#ifdef _WIN32
    (void)sock_ptr;
    (void)data;
    cct_rt_fail("sock_send unsupported on _WIN32");
    return 0LL;
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_send recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_send recebeu socket fechado");
    const char *src = data ? data : "";
    size_t total = strlen(src);
    size_t sent = 0U;
    while (sent < total) {
        ssize_t rc = send(sock->fd, src + sent, total - sent, 0);
        if (rc > 0) {
            sent += (size_t)rc;
            continue;
        }
        if (rc < 0 && errno == EINTR) continue;
        cct_rt_socket_set_last_error("sock_send falhou");
        cct_rt_fail("sock_send falhou");
    }
    cct_rt_socket_clear_last_error();
    return (long long)sent;
#endif
}

static char *cct_rt_sock_recv(void *sock_ptr, long long max_bytes) {
#ifdef _WIN32
    (void)sock_ptr;
    (void)max_bytes;
    cct_rt_fail("sock_recv unsupported on _WIN32");
    return "";
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_recv recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_recv recebeu socket fechado");
    if (max_bytes < 0) cct_rt_fail("sock_recv max_bytes invalido");
    if (max_bytes == 0) return cct_rt_socket_empty_string();
    char *buf = (char*)cct_rt_alloc_or_fail((size_t)max_bytes + 1U);
    for (;;) {
        ssize_t rc = recv(sock->fd, buf, (size_t)max_bytes, 0);
        if (rc > 0) {
            buf[rc] = '\0';
            cct_rt_socket_clear_last_error();
            return buf;
        }
        if (rc == 0) {
            buf[0] = '\0';
            cct_rt_socket_clear_last_error();
            return buf;
        }
        if (errno == EINTR) continue;
        if (errno == EAGAIN || errno == EWOULDBLOCK) {
            cct_rt_free_ptr(buf);
            cct_rt_socket_clear_last_error();
            return cct_rt_socket_empty_string();
        }
        cct_rt_free_ptr(buf);
        cct_rt_socket_set_last_error("sock_recv falhou");
        cct_rt_fail("sock_recv falhou");
    }
#endif
}

static void cct_rt_sock_close(void *sock_ptr) {
#ifdef _WIN32
    (void)sock_ptr;
    cct_rt_fail("sock_close unsupported on _WIN32");
#else
    cct_rt_socket_t *sock = (cct_rt_socket_t*)sock_ptr;
    if (!sock) return;
    if (!sock->closed && sock->fd >= 0) {
        while (close(sock->fd) != 0) {
            if (errno == EINTR) continue;
            break;
        }
    }
    if (sock->owns_unix_path && sock->unix_path[0]) {
        (void)unlink(sock->unix_path);
    }
    sock->fd = -1;
    sock->closed = 1;
    sock->owns_unix_path = 0;
    sock->unix_path[0] = '\0';
#endif
}

static void cct_rt_sock_set_timeout_ms(void *sock_ptr, long long timeout_ms) {
#ifdef _WIN32
    (void)sock_ptr;
    (void)timeout_ms;
    cct_rt_fail("sock_set_timeout_ms unsupported on _WIN32");
#else
    cct_rt_socket_t *sock = cct_rt_socket_require(sock_ptr, "sock_set_timeout_ms recebeu socket nulo");
    cct_rt_socket_check_open(sock, "sock_set_timeout_ms recebeu socket fechado");
    if (timeout_ms < 0) cct_rt_fail("sock_set_timeout_ms invalido");
    struct timeval tv;
    tv.tv_sec = (time_t)(timeout_ms / 1000LL);
    tv.tv_usec = (suseconds_t)((timeout_ms % 1000LL) * 1000LL);
    if (setsockopt(sock->fd, SOL_SOCKET, SO_RCVTIMEO, &tv, (socklen_t)sizeof(tv)) != 0) {
        cct_rt_socket_set_last_error("sock_set_timeout_ms recv falhou");
        cct_rt_fail("sock_set_timeout_ms recv falhou");
    }
    if (setsockopt(sock->fd, SOL_SOCKET, SO_SNDTIMEO, &tv, (socklen_t)sizeof(tv)) != 0) {
        cct_rt_socket_set_last_error("sock_set_timeout_ms send falhou");
        cct_rt_fail("sock_set_timeout_ms send falhou");
    }
    cct_rt_socket_clear_last_error();
#endif
}

/* ===== Crypto Runtime Helpers (FASE 32A) ===== */
static void cct_rt_crypto_secure_zero(void *ptr, size_t len) {
    if (!ptr || len == 0U) return;
    volatile unsigned char *p = (volatile unsigned char*)ptr;
    while (len--) *p++ = 0U;
}

static char *cct_rt_crypto_hex_encode(const unsigned char *bytes, size_t len) {
    static const char digits[] = "0123456789abcdef";
    char *hex = (char*)cct_rt_alloc_or_fail((len * 2U) + 1U);
    for (size_t i = 0; i < len; i++) {
        unsigned char b = bytes[i];
        hex[i * 2U] = digits[(b >> 4) & 0x0FU];
        hex[i * 2U + 1U] = digits[b & 0x0FU];
    }
    hex[len * 2U] = '\0';
    return hex;
}

static cct_rt_bytes_t *cct_rt_crypto_require_bytes(void *ptr, const char *ctx) {
    return cct_rt_bytes_require(ptr, ctx ? ctx : "crypto bytes buffer invalido");
}

static char *cct_rt_crypto_sha256_text(const char *text) {
    const unsigned char *data = (const unsigned char*)((text) ? text : "");
    unsigned char digest[32];
    if (!SHA256(data, strlen((const char*)data), digest)) cct_rt_fail("crypto sha256 failed");
    return cct_rt_crypto_hex_encode(digest, sizeof(digest));
}

static char *cct_rt_crypto_sha256_bytes(void *ptr, long long length) {
    if (length < 0) cct_rt_fail("crypto sha256_bytes expects length >= 0");
    cct_rt_bytes_t *bytes = cct_rt_crypto_require_bytes(ptr, "crypto sha256_bytes recebeu buffer nulo");
    if (length > bytes->len) cct_rt_fail("crypto sha256_bytes length exceeds buffer size");
    unsigned char digest[32];
    if (!SHA256(bytes->data ? bytes->data : (const unsigned char*)"", (size_t)length, digest)) cct_rt_fail("crypto sha256_bytes failed");
    return cct_rt_crypto_hex_encode(digest, sizeof(digest));
}

static char *cct_rt_crypto_sha512_text(const char *text) {
    const unsigned char *data = (const unsigned char*)((text) ? text : "");
    unsigned char digest[64];
    if (!SHA512(data, strlen((const char*)data), digest)) cct_rt_fail("crypto sha512 failed");
    return cct_rt_crypto_hex_encode(digest, sizeof(digest));
}

static char *cct_rt_crypto_sha512_bytes(void *ptr, long long length) {
    if (length < 0) cct_rt_fail("crypto sha512_bytes expects length >= 0");
    cct_rt_bytes_t *bytes = cct_rt_crypto_require_bytes(ptr, "crypto sha512_bytes recebeu buffer nulo");
    if (length > bytes->len) cct_rt_fail("crypto sha512_bytes length exceeds buffer size");
    unsigned char digest[64];
    if (!SHA512(bytes->data ? bytes->data : (const unsigned char*)"", (size_t)length, digest)) cct_rt_fail("crypto sha512_bytes failed");
    return cct_rt_crypto_hex_encode(digest, sizeof(digest));
}

static char *cct_rt_crypto_hmac_sha256(const char *key, const char *message) {
    unsigned char digest[EVP_MAX_MD_SIZE];
    unsigned int digest_len = 0U;
    const char *key_s = key ? key : "";
    const char *msg_s = message ? message : "";
    if (!HMAC(EVP_sha256(), key_s, (int)strlen(key_s), (const unsigned char*)msg_s, strlen(msg_s), digest, &digest_len)) cct_rt_fail("crypto hmac_sha256 failed");
    return cct_rt_crypto_hex_encode(digest, digest_len);
}

static char *cct_rt_crypto_hmac_sha512(const char *key, const char *message) {
    unsigned char digest[EVP_MAX_MD_SIZE];
    unsigned int digest_len = 0U;
    const char *key_s = key ? key : "";
    const char *msg_s = message ? message : "";
    if (!HMAC(EVP_sha512(), key_s, (int)strlen(key_s), (const unsigned char*)msg_s, strlen(msg_s), digest, &digest_len)) cct_rt_fail("crypto hmac_sha512 failed");
    return cct_rt_crypto_hex_encode(digest, digest_len);
}

static char *cct_rt_crypto_pbkdf2_sha256(const char *password, const char *salt, long long iterations, long long key_length) {
    const char *pwd = password ? password : "";
    const char *salt_s = salt ? salt : "";
    if (iterations < 100000LL) cct_rt_fail("crypto pbkdf2_sha256 requires at least 100000 iterations");
    if (strlen(salt_s) < 16U) cct_rt_fail("crypto pbkdf2_sha256 requires salt length >= 16");
    if (key_length < 16LL) cct_rt_fail("crypto pbkdf2_sha256 requires key_length >= 16");
    unsigned char *derived = (unsigned char*)cct_rt_alloc_or_fail((size_t)key_length);
    if (PKCS5_PBKDF2_HMAC(pwd, (int)strlen(pwd), (const unsigned char*)salt_s, (int)strlen(salt_s), (int)iterations, EVP_sha256(), (int)key_length, derived) != 1) {
        cct_rt_crypto_secure_zero(derived, (size_t)key_length);
        cct_rt_free_ptr(derived);
        cct_rt_fail("crypto pbkdf2_sha256 failed");
    }
    char *hex = cct_rt_crypto_hex_encode(derived, (size_t)key_length);
    cct_rt_crypto_secure_zero(derived, (size_t)key_length);
    cct_rt_free_ptr(derived);
    return hex;
}

static void *cct_rt_crypto_csprng_bytes(long long count) {
    if (count < 0) cct_rt_fail("crypto csprng_bytes expects count >= 0");
    cct_rt_bytes_t *bytes = (cct_rt_bytes_t*)cct_rt_bytes_new(count);
    if (count == 0) return bytes;
    if (RAND_bytes(bytes->data, (int)count) != 1) cct_rt_fail("crypto csprng_bytes failed");
    return bytes;
}

static long long cct_rt_crypto_constant_time_compare(const char *a, const char *b) {
    const unsigned char *aa = (const unsigned char*)((a) ? a : "");
    const unsigned char *bb = (const unsigned char*)((b) ? b : "");
    size_t len_a = strlen((const char*)aa);
    size_t len_b = strlen((const char*)bb);
    size_t max_len = (len_a > len_b) ? len_a : len_b;
    unsigned int diff = (unsigned int)(len_a ^ len_b);
    for (size_t i = 0; i < max_len; i++) {
        unsigned char va = (i < len_a) ? aa[i] : 0U;
        unsigned char vb = (i < len_b) ? bb[i] : 0U;
        diff |= (unsigned int)(va ^ vb);
    }
    return diff == 0U ? 1LL : 0LL;
}

typedef struct {
    regex_t compiled;
    long long flags;
} cct_rt_regex_t;

static char cct_rt_regex_last_error_buf[256] = {0};

static void cct_rt_regex_set_error(const char *msg) {
    snprintf(cct_rt_regex_last_error_buf, sizeof(cct_rt_regex_last_error_buf), "%s", (msg && *msg) ? msg : "regex failure");
}

static char *cct_rt_regex_dup_span(const char *src, size_t len) {
    char *out_s = (char*)cct_rt_alloc_or_fail(len + 1u);
    if (len > 0u) memcpy(out_s, src, len);
    out_s[len] = '\0';
    return out_s;
}

static void cct_rt_regex_push_verbum(void *flux_ptr, const char *src, size_t len) {
    char *copy = cct_rt_regex_dup_span(src, len);
    cct_rt_fluxus_push(flux_ptr, (const void*)&copy);
}

static void *cct_rt_regex_compile(const char *pattern, long long flags) {
    cct_rt_regex_t *rx = (cct_rt_regex_t*)cct_rt_alloc_or_fail(sizeof(cct_rt_regex_t));
    int cflags = REG_EXTENDED;
    if (flags & 1LL) cflags |= REG_ICASE;
    if (flags & 2LL) cflags |= REG_NEWLINE;
    int rc = regcomp(&rx->compiled, pattern ? pattern : "", cflags);
    if (rc != 0) {
        regerror(rc, &rx->compiled, cct_rt_regex_last_error_buf, sizeof(cct_rt_regex_last_error_buf));
        cct_rt_free_ptr(rx);
        return NULL;
    }
    rx->flags = flags;
    cct_rt_regex_last_error_buf[0] = '\0';
    return rx;
}

static char *cct_rt_regex_last_error(void) {
    return cct_rt_regex_last_error_buf;
}

static long long cct_rt_regex_match(void *handle, const char *text) {
    if (!handle) return 0LL;
    cct_rt_regex_t *rx = (cct_rt_regex_t*)handle;
    regmatch_t match;
    int rc = regexec(&rx->compiled, text ? text : "", 1, &match, 0);
    if (rc != 0) return 0LL;
    size_t len = strlen(text ? text : "");
    return (match.rm_so == 0 && match.rm_eo == (regoff_t)len) ? 1LL : 0LL;
}

static char *cct_rt_regex_search(void *handle, const char *text) {
    if (!handle) return cct_rt_regex_dup_span("", 0u);
    cct_rt_regex_t *rx = (cct_rt_regex_t*)handle;
    regmatch_t match;
    const char *src = text ? text : "";
    int rc = regexec(&rx->compiled, src, 1, &match, 0);
    if (rc != 0 || match.rm_so < 0 || match.rm_eo < match.rm_so) return cct_rt_regex_dup_span("", 0u);
    return cct_rt_regex_dup_span(src + match.rm_so, (size_t)(match.rm_eo - match.rm_so));
}

static void *cct_rt_regex_find_all(void *handle, const char *text) {
    void *flux = cct_rt_fluxus_create((long long)sizeof(char*));
    if (!handle) return flux;
    cct_rt_regex_t *rx = (cct_rt_regex_t*)handle;
    const char *cursor = text ? text : "";
    size_t offset = 0u;
    size_t total_len = strlen(cursor);
    while (offset <= total_len) {
        regmatch_t match;
        int rc = regexec(&rx->compiled, cursor + offset, 1, &match, 0);
        if (rc != 0 || match.rm_so < 0 || match.rm_eo < match.rm_so) break;
        size_t start = offset + (size_t)match.rm_so;
        size_t end = offset + (size_t)match.rm_eo;
        cct_rt_regex_push_verbum(flux, cursor + start, end - start);
        if (match.rm_eo == match.rm_so) {
            if (offset == total_len) break;
            offset += 1u;
        } else {
            offset = end;
        }
    }
    return flux;
}

static char *cct_rt_regex_replace(void *handle, const char *text, const char *replacement, long long all) {
    if (!handle) return cct_rt_regex_dup_span(text ? text : "", strlen(text ? text : ""));
    cct_rt_regex_t *rx = (cct_rt_regex_t*)handle;
    const char *src = text ? text : "";
    const char *rep = replacement ? replacement : "";
    size_t src_len = strlen(src);
    size_t rep_len = strlen(rep);
    size_t cap = src_len + rep_len + 16u;
    char *out_s = (char*)cct_rt_alloc_or_fail(cap);
    size_t out_len = 0u;
    size_t offset = 0u;
    while (offset <= src_len) {
        regmatch_t match;
        int rc = regexec(&rx->compiled, src + offset, 1, &match, 0);
        if (rc != 0 || match.rm_so < 0 || match.rm_eo < match.rm_so) break;
        size_t start = offset + (size_t)match.rm_so;
        size_t end = offset + (size_t)match.rm_eo;
        size_t prefix = start - offset;
        while (out_len + prefix + rep_len + 1u > cap) { cap *= 2u; out_s = (char*)realloc(out_s, cap); if (!out_s) cct_rt_fail("regex replace realloc failed"); }
        if (prefix > 0u) memcpy(out_s + out_len, src + offset, prefix);
        out_len += prefix;
        if (rep_len > 0u) memcpy(out_s + out_len, rep, rep_len);
        out_len += rep_len;
        if (!all) { offset = end; break; }
        if (match.rm_eo == match.rm_so) {
            if (offset == src_len) break;
            while (out_len + 2u > cap) { cap *= 2u; out_s = (char*)realloc(out_s, cap); if (!out_s) cct_rt_fail("regex replace realloc failed"); }
            out_s[out_len++] = src[offset];
            offset += 1u;
        } else {
            offset = end;
        }
    }
    if (offset < src_len) {
        size_t tail = src_len - offset;
        while (out_len + tail + 1u > cap) { cap *= 2u; out_s = (char*)realloc(out_s, cap); if (!out_s) cct_rt_fail("regex replace realloc failed"); }
        memcpy(out_s + out_len, src + offset, tail);
        out_len += tail;
    }
    out_s[out_len] = '\0';
    return out_s;
}

static void *cct_rt_regex_split(void *handle, const char *text) {
    void *flux = cct_rt_fluxus_create((long long)sizeof(char*));
    const char *src = text ? text : "";
    if (!handle) {
        cct_rt_regex_push_verbum(flux, src, strlen(src));
        return flux;
    }
    cct_rt_regex_t *rx = (cct_rt_regex_t*)handle;
    size_t src_len = strlen(src);
    size_t offset = 0u;
    while (offset <= src_len) {
        regmatch_t match;
        int rc = regexec(&rx->compiled, src + offset, 1, &match, 0);
        if (rc != 0 || match.rm_so < 0 || match.rm_eo < match.rm_so) break;
        size_t start = offset + (size_t)match.rm_so;
        size_t end = offset + (size_t)match.rm_eo;
        cct_rt_regex_push_verbum(flux, src + offset, start - offset);
        if (match.rm_eo == match.rm_so) {
            if (offset == src_len) break;
            offset += 1u;
        } else {
            offset = end;
        }
    }
    cct_rt_regex_push_verbum(flux, src + offset, src_len - offset);
    return flux;
}

static void cct_rt_regex_free(void *handle) {
    if (!handle) return;
    cct_rt_regex_t *rx = (cct_rt_regex_t*)handle;
    regfree(&rx->compiled);
    cct_rt_free_ptr(rx);
}

#ifdef _WIN32
static char *cct_rt_mail_smtp_send(const char *host, long long port, const char *username, const char *password, long long auth_kind, long long use_starttls, long long use_smtps, const char *mail_from, const char *rcpts_text, const char *mime_text) {
    (void)host; (void)port; (void)username; (void)password; (void)auth_kind; (void)use_starttls; (void)use_smtps; (void)mail_from; (void)rcpts_text; (void)mime_text;
    const char *msg = "SMTP host runtime indisponivel neste target";
    size_t n = strlen(msg);
    char *out_s = (char*)cct_rt_alloc_or_fail(n + 1U);
    memcpy(out_s, msg, n + 1U);
    return out_s;
}
#else
typedef struct {
    int fd;
    int use_tls;
    SSL_CTX *ssl_ctx;
    SSL *ssl;
    char last_error[512];
} cct_rt_mail_conn_t;

static void cct_rt_mail_copy_error(char *dst, size_t cap, const char *msg) {
    const char *src = msg ? msg : "";
    size_t n = strlen(src);
    if (cap == 0) return;
    if (n >= cap) n = cap - 1U;
    memcpy(dst, src, n);
    dst[n] = '\0';
}

static char *cct_rt_mail_dup_cstr(const char *src) {
    const char *text = src ? src : "";
    size_t n = strlen(text);
    char *out_s = (char*)cct_rt_alloc_or_fail(n + 1U);
    memcpy(out_s, text, n + 1U);
    return out_s;
}

static void cct_rt_mail_set_error(cct_rt_mail_conn_t *conn, const char *msg) {
    if (!conn) return;
    cct_rt_mail_copy_error(conn->last_error, sizeof(conn->last_error), msg);
}

static int cct_rt_mail_socket_close(int fd) {
    if (fd < 0) return 0;
    return close(fd);
}

static void cct_rt_mail_conn_init(cct_rt_mail_conn_t *conn) {
    if (!conn) return;
    conn->fd = -1;
    conn->use_tls = 0;
    conn->ssl_ctx = NULL;
    conn->ssl = NULL;
    conn->last_error[0] = '\0';
}

static void cct_rt_mail_conn_close(cct_rt_mail_conn_t *conn) {
    if (!conn) return;
    if (conn->ssl) {
        SSL_shutdown(conn->ssl);
        SSL_free(conn->ssl);
        conn->ssl = NULL;
    }
    if (conn->ssl_ctx) {
        SSL_CTX_free(conn->ssl_ctx);
        conn->ssl_ctx = NULL;
    }
    if (conn->fd >= 0) {
        cct_rt_mail_socket_close(conn->fd);
        conn->fd = -1;
    }
    conn->use_tls = 0;
}

static int cct_rt_mail_base64_raw(const unsigned char *src, size_t src_len, char *dst, size_t dst_cap) {
    size_t need = ((src_len + 2U) / 3U) * 4U + 1U;
    int out_len = 0;
    if (!dst || dst_cap < need) return 0;
    out_len = EVP_EncodeBlock((unsigned char*)dst, src, (int)src_len);
    if (out_len < 0) return 0;
    dst[(size_t)out_len] = '\0';
    return 1;
}

static int cct_rt_mail_base64_text(const char *src, char *dst, size_t dst_cap) {
    const unsigned char *bytes = (const unsigned char*)(src ? src : "");
    return cct_rt_mail_base64_raw(bytes, strlen((const char*)bytes), dst, dst_cap);
}

static int cct_rt_mail_base64_auth_plain(const char *username, const char *password, char *dst, size_t dst_cap) {
    const char *user = username ? username : "";
    const char *pass = password ? password : "";
    size_t user_len = strlen(user);
    size_t pass_len = strlen(pass);
    size_t raw_len = 1U + user_len + 1U + pass_len;
    unsigned char *raw = (unsigned char*)cct_rt_alloc_or_fail(raw_len ? raw_len : 1U);
    size_t off = 0;
    raw[off++] = 0U;
    if (user_len > 0) memcpy(raw + off, user, user_len);
    off += user_len;
    raw[off++] = 0U;
    if (pass_len > 0) memcpy(raw + off, pass, pass_len);
    off += pass_len;
    int ok = cct_rt_mail_base64_raw(raw, off, dst, dst_cap);
    cct_rt_free_ptr(raw);
    return ok;
}

static int cct_rt_mail_conn_read(cct_rt_mail_conn_t *conn, void *buf, size_t len) {
    if (!conn || conn->fd < 0) return -1;
    if (conn->use_tls) return SSL_read(conn->ssl, buf, (int)len);
    return (int)recv(conn->fd, buf, len, 0);
}

static int cct_rt_mail_conn_write(cct_rt_mail_conn_t *conn, const void *buf, size_t len) {
    if (!conn || conn->fd < 0) return -1;
    if (conn->use_tls) return SSL_write(conn->ssl, buf, (int)len);
    return (int)send(conn->fd, buf, len, 0);
}

static int cct_rt_mail_write_all(cct_rt_mail_conn_t *conn, const char *buf, size_t len) {
    size_t off = 0;
    while (off < len) {
        int n = cct_rt_mail_conn_write(conn, buf + off, len - off);
        if (n <= 0) {
            cct_rt_mail_set_error(conn, "falha ao escrever no socket SMTP");
            return 0;
        }
        off += (size_t)n;
    }
    return 1;
}

static int cct_rt_mail_read_line(cct_rt_mail_conn_t *conn, char *line, size_t cap) {
    size_t used = 0;
    if (!line || cap == 0) return 0;
    while (used + 1U < cap) {
        char ch = 0;
        int n = cct_rt_mail_conn_read(conn, &ch, 1U);
        if (n <= 0) {
            cct_rt_mail_set_error(conn, "falha ao ler resposta SMTP");
            return 0;
        }
        line[used++] = ch;
        if (ch == '\n') break;
    }
    line[used] = '\0';
    while (used > 0 && (line[used - 1] == '\n' || line[used - 1] == '\r')) {
        line[--used] = '\0';
    }
    return 1;
}

static int cct_rt_mail_read_response(cct_rt_mail_conn_t *conn, char *message, size_t message_cap) {
    int code = -1;
    char line[1024];
    if (message && message_cap > 0) message[0] = '\0';
    for (;;) {
        if (!cct_rt_mail_read_line(conn, line, sizeof(line))) return -1;
        if (isdigit((unsigned char)line[0]) && isdigit((unsigned char)line[1]) && isdigit((unsigned char)line[2])) {
            code = (line[0] - '0') * 100 + (line[1] - '0') * 10 + (line[2] - '0');
            if (message && message_cap > 0) {
                const char *text = line[3] ? line + 4 : line;
                cct_rt_mail_copy_error(message, message_cap, text);
            }
            if (line[3] == ' ') return code;
            if (line[3] == '-') continue;
            return code;
        }
        if (message && message_cap > 0) cct_rt_mail_copy_error(message, message_cap, line);
    }
}

static int cct_rt_mail_expect_code(cct_rt_mail_conn_t *conn, int expected, const char *ctx) {
    char message[512];
    int code = cct_rt_mail_read_response(conn, message, sizeof(message));
    if (code != expected) {
        char buf[512];
        snprintf(buf, sizeof(buf), "%s: SMTP %d %s", ctx ? ctx : "SMTP erro", code, message);
        cct_rt_mail_set_error(conn, buf);
        return 0;
    }
    return 1;
}

static int cct_rt_mail_expect_class(cct_rt_mail_conn_t *conn, int klass, const char *ctx) {
    char message[512];
    int code = cct_rt_mail_read_response(conn, message, sizeof(message));
    if (code < 0 || (code / 100) != klass) {
        char buf[512];
        snprintf(buf, sizeof(buf), "%s: SMTP %d %s", ctx ? ctx : "SMTP erro", code, message);
        cct_rt_mail_set_error(conn, buf);
        return 0;
    }
    return 1;
}

static int cct_rt_mail_send_command(cct_rt_mail_conn_t *conn, const char *text) {
    size_t len = strlen(text ? text : "");
    if (!cct_rt_mail_write_all(conn, text ? text : "", len)) return 0;
    return cct_rt_mail_write_all(conn, "\r\n", 2U);
}

static int cct_rt_mail_connect_tcp(cct_rt_mail_conn_t *conn, const char *host, long long port) {
    struct addrinfo hints;
    struct addrinfo *res = NULL;
    struct addrinfo *it = NULL;
    char port_text[32];
    memset(&hints, 0, sizeof(hints));
    hints.ai_family = AF_UNSPEC;
    hints.ai_socktype = SOCK_STREAM;
    snprintf(port_text, sizeof(port_text), "%lld", port);
    if (getaddrinfo((host && *host) ? host : "127.0.0.1", port_text, &hints, &res) != 0) {
        cct_rt_mail_set_error(conn, "falha ao resolver host SMTP");
        return 0;
    }
    for (it = res; it; it = it->ai_next) {
        int fd = socket(it->ai_family, it->ai_socktype, it->ai_protocol);
        if (fd < 0) continue;
        if (connect(fd, it->ai_addr, it->ai_addrlen) == 0) {
            conn->fd = fd;
            freeaddrinfo(res);
            return 1;
        }
        cct_rt_mail_socket_close(fd);
    }
    freeaddrinfo(res);
    cct_rt_mail_set_error(conn, "falha ao conectar ao servidor SMTP");
    return 0;
}

static int cct_rt_mail_enable_tls(cct_rt_mail_conn_t *conn, const char *host) {
    SSL_CTX *ctx = NULL;
    SSL *ssl = NULL;
    OPENSSL_init_ssl(0, NULL);
    ctx = SSL_CTX_new(TLS_client_method());
    if (!ctx) {
        cct_rt_mail_set_error(conn, "falha ao criar contexto TLS SMTP");
        return 0;
    }
    SSL_CTX_set_verify(ctx, SSL_VERIFY_NONE, NULL);
    ssl = SSL_new(ctx);
    if (!ssl) {
        SSL_CTX_free(ctx);
        cct_rt_mail_set_error(conn, "falha ao criar sessao TLS SMTP");
        return 0;
    }
    if (host && *host) SSL_set_tlsext_host_name(ssl, host);
    SSL_set_fd(ssl, conn->fd);
    if (SSL_connect(ssl) != 1) {
        SSL_free(ssl);
        SSL_CTX_free(ctx);
        cct_rt_mail_set_error(conn, "handshake TLS SMTP falhou");
        return 0;
    }
    conn->ssl_ctx = ctx;
    conn->ssl = ssl;
    conn->use_tls = 1;
    return 1;
}

static void cct_rt_mail_get_ehlo_name(char *buf, size_t cap) {
    if (!buf || cap == 0) return;
    if (gethostname(buf, cap - 1U) != 0 || buf[0] == '\0') {
        cct_rt_mail_copy_error(buf, cap, "localhost");
        return;
    }
    buf[cap - 1U] = '\0';
}

static int cct_rt_mail_send_mail_from(cct_rt_mail_conn_t *conn, const char *mail_from) {
    char cmd[1024];
    snprintf(cmd, sizeof(cmd), "MAIL FROM:<%s>", (mail_from && *mail_from) ? mail_from : "");
    if (!cct_rt_mail_send_command(conn, cmd)) return 0;
    return cct_rt_mail_expect_class(conn, 2, "MAIL FROM rejeitado");
}

static int cct_rt_mail_send_recipients(cct_rt_mail_conn_t *conn, const char *rcpts_text) {
    const char *src = rcpts_text ? rcpts_text : "";
    const char *line = src;
    int count = 0;
    while (*line) {
        const char *end = line;
        char addr[512];
        size_t len = 0;
        char cmd[640];
        while (*end && *end != '\n' && *end != '\r') end++;
        len = (size_t)(end - line);
        if (len > 0) {
            if (len >= sizeof(addr)) len = sizeof(addr) - 1U;
            memcpy(addr, line, len);
            addr[len] = '\0';
            snprintf(cmd, sizeof(cmd), "RCPT TO:<%s>", addr);
            if (!cct_rt_mail_send_command(conn, cmd)) return 0;
            if (!cct_rt_mail_expect_class(conn, 2, "RCPT TO rejeitado")) return 0;
            count++;
        }
        while (*end == '\n' || *end == '\r') end++;
        line = end;
    }
    if (count == 0) {
        cct_rt_mail_set_error(conn, "nenhum destinatario SMTP informado");
        return 0;
    }
    return 1;
}

static char *cct_rt_mail_dotstuff(const char *mime_text) {
    const char *src = mime_text ? mime_text : "";
    size_t n = strlen(src);
    size_t cap = n * 2U + 8U;
    char *out_s = (char*)cct_rt_alloc_or_fail(cap);
    size_t i = 0;
    size_t j = 0;
    int at_line_start = 1;
    while (i < n) {
        char ch = src[i];
        if (at_line_start && ch == '.') out_s[j++] = '.';
        if (ch == '\r') {
            out_s[j++] = '\r';
            out_s[j++] = '\n';
            if ((i + 1U) < n && src[i + 1U] == '\n') i++;
            at_line_start = 1;
        } else if (ch == '\n') {
            out_s[j++] = '\r';
            out_s[j++] = '\n';
            at_line_start = 1;
        } else {
            out_s[j++] = ch;
            at_line_start = 0;
        }
        i++;
    }
    if (j < 2U || out_s[j - 2U] != '\r' || out_s[j - 1U] != '\n') {
        out_s[j++] = '\r';
        out_s[j++] = '\n';
    }
    out_s[j] = '\0';
    return out_s;
}

static int cct_rt_mail_send_data(cct_rt_mail_conn_t *conn, const char *mime_text) {
    char *payload = NULL;
    if (!cct_rt_mail_send_command(conn, "DATA")) return 0;
    if (!cct_rt_mail_expect_code(conn, 354, "DATA rejeitado")) return 0;
    payload = cct_rt_mail_dotstuff(mime_text);
    if (!cct_rt_mail_write_all(conn, payload, strlen(payload))) {
        cct_rt_free_ptr(payload);
        return 0;
    }
    cct_rt_free_ptr(payload);
    if (!cct_rt_mail_write_all(conn, ".\r\n", 3U)) return 0;
    return cct_rt_mail_expect_class(conn, 2, "DATA final rejeitado");
}

static int cct_rt_mail_auth_plain(cct_rt_mail_conn_t *conn, const char *username, const char *password) {
    char payload[1024];
    char cmd[1200];
    if (!cct_rt_mail_base64_auth_plain(username, password, payload, sizeof(payload))) {
        cct_rt_mail_set_error(conn, "falha ao codificar AUTH PLAIN");
        return 0;
    }
    snprintf(cmd, sizeof(cmd), "AUTH PLAIN %s", payload);
    if (!cct_rt_mail_send_command(conn, cmd)) return 0;
    return cct_rt_mail_expect_code(conn, 235, "AUTH PLAIN rejeitado");
}

static int cct_rt_mail_auth_login(cct_rt_mail_conn_t *conn, const char *username, const char *password) {
    char user64[768];
    char pass64[768];
    if (!cct_rt_mail_base64_text(username, user64, sizeof(user64)) || !cct_rt_mail_base64_text(password, pass64, sizeof(pass64))) {
        cct_rt_mail_set_error(conn, "falha ao codificar AUTH LOGIN");
        return 0;
    }
    if (!cct_rt_mail_send_command(conn, "AUTH LOGIN")) return 0;
    if (!cct_rt_mail_expect_code(conn, 334, "AUTH LOGIN username rejeitado")) return 0;
    if (!cct_rt_mail_send_command(conn, user64)) return 0;
    if (!cct_rt_mail_expect_code(conn, 334, "AUTH LOGIN password rejeitado")) return 0;
    if (!cct_rt_mail_send_command(conn, pass64)) return 0;
    return cct_rt_mail_expect_code(conn, 235, "AUTH LOGIN rejeitado");
}

static int cct_rt_mail_auth_xoauth2(cct_rt_mail_conn_t *conn, const char *username, const char *password) {
    const char *user = username ? username : "";
    const char *token = password ? password : "";
    const char *prefix_a = "user=";
    const char *prefix_b = "\x01auth=Bearer ";
    const char *suffix = "\x01\x01";
    size_t raw_len = strlen(prefix_a) + strlen(user) + strlen(prefix_b) + strlen(token) + strlen(suffix);
    unsigned char *raw = (unsigned char*)cct_rt_alloc_or_fail(raw_len + 1U);
    char payload[2048];
    char cmd[2300];
    size_t off = 0;
    memcpy(raw + off, prefix_a, strlen(prefix_a)); off += strlen(prefix_a);
    memcpy(raw + off, user, strlen(user)); off += strlen(user);
    memcpy(raw + off, prefix_b, strlen(prefix_b)); off += strlen(prefix_b);
    memcpy(raw + off, token, strlen(token)); off += strlen(token);
    memcpy(raw + off, suffix, strlen(suffix)); off += strlen(suffix);
    raw[off] = '\0';
    if (!cct_rt_mail_base64_raw(raw, off, payload, sizeof(payload))) {
        cct_rt_free_ptr(raw);
        cct_rt_mail_set_error(conn, "falha ao codificar AUTH XOAUTH2");
        return 0;
    }
    cct_rt_free_ptr(raw);
    snprintf(cmd, sizeof(cmd), "AUTH XOAUTH2 %s", payload);
    if (!cct_rt_mail_send_command(conn, cmd)) return 0;
    return cct_rt_mail_expect_code(conn, 235, "AUTH XOAUTH2 rejeitado");
}

static int cct_rt_mail_authenticate(cct_rt_mail_conn_t *conn, long long auth_kind, const char *username, const char *password) {
    if (auth_kind == 0) return 1;
    if (!(username && *username) || !(password && *password)) {
        cct_rt_mail_set_error(conn, "credenciais SMTP ausentes");
        return 0;
    }
    if (auth_kind == 1) return cct_rt_mail_auth_plain(conn, username, password);
    if (auth_kind == 2) return cct_rt_mail_auth_login(conn, username, password);
    if (auth_kind == 3) return cct_rt_mail_auth_xoauth2(conn, username, password);
    cct_rt_mail_set_error(conn, "modo de autenticacao SMTP desconhecido");
    return 0;
}

static char *cct_rt_mail_smtp_send(const char *host, long long port, const char *username, const char *password, long long auth_kind, long long use_starttls, long long use_smtps, const char *mail_from, const char *rcpts_text, const char *mime_text) {
    cct_rt_mail_conn_t conn;
    char ehlo_host[256];
    char cmd[512];
    cct_rt_mail_conn_init(&conn);
    if (!(mail_from && *mail_from)) return cct_rt_mail_dup_cstr("MAIL FROM ausente");
    if (!rcpts_text || !*rcpts_text) return cct_rt_mail_dup_cstr("nenhum destinatario SMTP informado");
    if (port <= 0) port = use_smtps ? 465LL : (use_starttls ? 587LL : 25LL);
    if (!cct_rt_mail_connect_tcp(&conn, host, port)) goto fail;
    if (use_smtps) {
        if (!cct_rt_mail_enable_tls(&conn, host)) goto fail;
    }
    if (!cct_rt_mail_expect_code(&conn, 220, "banner SMTP invalido")) goto fail;
    cct_rt_mail_get_ehlo_name(ehlo_host, sizeof(ehlo_host));
    snprintf(cmd, sizeof(cmd), "EHLO %s", ehlo_host);
    if (!cct_rt_mail_send_command(&conn, cmd)) goto fail;
    if (!cct_rt_mail_expect_class(&conn, 2, "EHLO rejeitado")) goto fail;
    if (use_starttls) {
        if (!cct_rt_mail_send_command(&conn, "STARTTLS")) goto fail;
        if (!cct_rt_mail_expect_code(&conn, 220, "STARTTLS rejeitado")) goto fail;
        if (!cct_rt_mail_enable_tls(&conn, host)) goto fail;
        snprintf(cmd, sizeof(cmd), "EHLO %s", ehlo_host);
        if (!cct_rt_mail_send_command(&conn, cmd)) goto fail;
        if (!cct_rt_mail_expect_class(&conn, 2, "EHLO apos STARTTLS rejeitado")) goto fail;
    }
    if (!cct_rt_mail_authenticate(&conn, auth_kind, username, password)) goto fail;
    if (!cct_rt_mail_send_mail_from(&conn, mail_from)) goto fail;
    if (!cct_rt_mail_send_recipients(&conn, rcpts_text)) goto fail;
    if (!cct_rt_mail_send_data(&conn, mime_text)) goto fail;
    cct_rt_mail_send_command(&conn, "QUIT");
    cct_rt_mail_expect_code(&conn, 221, "QUIT rejeitado");
    cct_rt_mail_conn_close(&conn);
    return cct_rt_mail_dup_cstr("");
fail:
    cct_rt_mail_conn_close(&conn);
    return cct_rt_mail_dup_cstr(conn.last_error);
}
#endif
